class Solution:
    def canChange(self, start: str, target: str) -> bool:
        s, t = start.replace("_", ""), target.replace("_", "")
        if s != t:
            return False
        l, r = 0, 0
        for i in range(len(start)):
            if start[i] == "L" and target[i] == "L":
                l = max(l, i)
            if start[i] == "R" and target[i] == "R":
                r = min(r, i)
        return l <= r
